// LoadOrganization loads the organizationHour's Organization into the .R struct
func (o *OrganizationHour) LoadOrganization(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.Organization = nil

	related, err := o.Organization(mods...).One(ctx, exec)
	if err != nil {
		return err
	}

	related.R.OrganizationHours = OrganizationHourSlice{o}

	o.R.Organization = related
	return nil
}

// LoadOrganization loads the organizationHour's Organization into the .R struct
func (os OrganizationHourSlice) LoadOrganization(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	organizations, err := os.Organization(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		for _, rel := range organizations {
			if !o.OrganizationID.IsValue() {
				continue
			}

			if o.OrganizationID.MustGet() != rel.ID {
				continue
			}

			rel.R.OrganizationHours = append(rel.R.OrganizationHours, o)

			o.R.Organization = rel
			break
		}
	}

	return nil
}

